function findMinMoves(machines) {
    let n = machines.length;
    let totalDresses = machines.reduce((a, b) => a + b, 0);
    if (totalDresses % n !== 0) return -1;
    let average = totalDresses / n;
    let moves = 0, imbalance = 0;

    for (let i = 0; i < n; i++) {
        imbalance += machines[i] - average;
        moves = Math.max(moves, Math.max(Math.abs(imbalance), machines[i] - average));
    }

    return moves;
}
```

    1. Calculate the total number of dresses and check if it can be evenly distributed among the machines. If it cannot, return -1.
2. Calculate the average number of dresses each machine should have.
3. Initialize the moves and imbalance count to 0.
4. Iterate through the machines and calculate the current imbalance for each machine.
5. Update the moves count by taking the maximum of the current moves, the absolute value of the current imbalance, and the difference between the current machine's dresses and the average value.
6. Return the moves count.

